import{_ as e,c as t,o as a,ae as r}from"./chunks/framework.B7Y1jjX-.js";const u=JSON.parse('{"title":"吴明翔-前端开发","description":"","frontmatter":{},"headers":[],"relativePath":"generated-notes/前端/面试/简历/9.3.25.md","filePath":"generated-notes/前端/面试/简历/9.3.25.md"}'),n={name:"generated-notes/前端/面试/简历/9.3.25.md"};function l(i,o,s,d,c,g){return a(),t("div",null,[...o[0]||(o[0]=[r('<h1 id="吴明翔-前端开发" tabindex="-1">吴明翔-前端开发 <a class="header-anchor" href="#吴明翔-前端开发" aria-label="Permalink to &quot;吴明翔-前端开发&quot;">​</a></h1><p><strong>联系方式</strong>： <a href="mailto:Danoday@Foxmail.com" target="_blank" rel="noreferrer">Danoday@Foxmail.com</a> 17845577339 19703319137 <strong>个人主页</strong>： GitHub <a href="https://github.com/DanoAndHolidays" target="_blank" rel="noreferrer">https://github.com/DanoAndHolidays</a></p><p><strong>中国矿业大学</strong> 计算机科学与技术 <strong>双一流211本科</strong> 2023-2027</p><ul><li><strong>科研竞赛</strong>：2025年度中国青年科技创新“揭榜挂帅”擂台赛、数学建模</li><li><strong>校园经历</strong>：中国矿业大学学生服务总队宣设部部长、副主席</li></ul><hr><h2 id="技术能力" tabindex="-1">技术能力 <a class="header-anchor" href="#技术能力" aria-label="Permalink to &quot;技术能力&quot;">​</a></h2><ul><li><strong>前端基础：</strong> 扎实掌握 HTML5、CSS3、JavaScript ES6+、浏览器运行原理、垃圾清理</li><li><strong>框架技术：</strong> 熟练使用Vue3，Vue Router和Pinia，了解组件化开发思想和生态系统</li><li><strong>开发工具：</strong> 熟练使用Vite、Git 等现代前端工程化工具</li><li><strong>UI框架：</strong> 熟悉Element Plus组件库的使用</li><li><strong>其他技能：</strong> 熟悉Sass、TailwindCSS、fontawesome、Echart、Axios、GSAP</li></ul><hr><h2 id="项目经验" tabindex="-1">项目经验 <a class="header-anchor" href="#项目经验" aria-label="Permalink to &quot;项目经验&quot;">​</a></h2><h4 id="一刻短剧-原playlet短剧" tabindex="-1">一刻短剧（原PlayLet短剧） <a class="header-anchor" href="#一刻短剧-原playlet短剧" aria-label="Permalink to &quot;一刻短剧（原PlayLet短剧）&quot;">​</a></h4><p><strong>技术栈：</strong><code>Vue3</code> / <code>Vue Router</code> / <code>Pinia</code>/<code>Sass</code>/<code>Echart</code>/<code>Axios</code>/<code>Element Plus</code><strong>项目描述：</strong> 基于Apifox公开项目API开发的短剧网站，一代使用纯原生开发，使用新的技术栈进行了二次开发。 <strong>主要职责：</strong></p><ul><li>实现了仿抖音的丝滑首页滑动，不影响流畅的情况下针对滚动进行了节流防抖优化，资源后台加载，减少滑动时的请求。</li><li>采用移动优先设计，响应式设计。</li><li>使用Axios进行二次封装与解耦，便于维护接口</li></ul><p><strong>原生版本</strong>：</p><ol><li>实现主页的无限滚动加载，并针对滚动进行了节流防抖优化</li><li>使用占位符动画填充正在加载的视频图片</li><li>使用flex布局实现响应式布局，适配多种设备屏幕。通过精心的色彩搭配，打造现代化的用户界面。</li></ol><h4 id="深岩智测-——基于多维信息感知的深部开采煤岩损伤演化预警平台" tabindex="-1">“深岩智测”——基于多维信息感知的深部开采煤岩损伤演化预警平台 <a class="header-anchor" href="#深岩智测-——基于多维信息感知的深部开采煤岩损伤演化预警平台" aria-label="Permalink to &quot;“深岩智测”——基于多维信息感知的深部开采煤岩损伤演化预警平台&quot;">​</a></h4><p><strong>技术栈：</strong> <code>Vue3</code> / <code>Vue Router</code> / <code>Pinia</code>/<code>Tailwindcss</code>/<code>Echart</code><strong>项目地址</strong>：<a href="https://danoandholidays.github.io/test/#/" target="_blank" rel="noreferrer">https://danoandholidays.github.io/test/#/</a><strong>项目描述：</strong> 数据可视化大屏，将模型输出的预测结果可视化展示 <strong>主要职责：</strong></p><ol><li>使用 Vue3 开发，封装针对不同数据的展示组件。通过响应式数据绑定，实现实时的数据展示。</li><li>使用 Pinia 进行状态管理，将模型的数据导入，实现跨组件的数据共享。学习了现代状态管理的最佳实践。</li></ol><hr><h2 id="自我评价" tabindex="-1">自我评价 <a class="header-anchor" href="#自我评价" aria-label="Permalink to &quot;自我评价&quot;">​</a></h2><ul><li><strong>学习能力强：</strong> 具备快速学习新技术的能力，关注前端技术发展趋势，持续提升技术水平</li><li><strong>实践经验丰富：</strong> 通过多个项目实践，积累了从设计到开发到部署的完整经验</li><li><strong>技术热情：</strong> 对前端技术充满热情，乐于分享和交流，希望在专业团队中快速成长</li></ul>',20)])])}const p=e(n,[["render",l]]);export{u as __pageData,p as default};
